import{_ as l,o as i,c as e,ak as t}from"./chunks/framework.24mNDJkT.js";const b=JSON.parse('{"title":"什么是链路","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/什么是链路.md","filePath":"计算机网络/物理层和数据链路层/什么是链路.md","lastUpdated":1775125132000}'),r={name:"计算机网络/物理层和数据链路层/什么是链路.md"};function s(h,a,n,o,d,c){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="什么是链路" tabindex="-1">什么是链路 <a class="header-anchor" href="#什么是链路" aria-label="Permalink to “什么是链路”">​</a></h1><h2 id="一、数据链路层的位置" tabindex="-1">一、数据链路层的位置 <a class="header-anchor" href="#一、数据链路层的位置" aria-label="Permalink to “一、数据链路层的位置”">​</a></h2><ul><li>位于五层模型中的<strong>第二层（自下而上）</strong></li><li>上一层：网络层</li><li>下一层：物理层</li></ul><p>分层结构：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层 → 运输层 → 网络层 → 数据链路层 → 物理层</span></span></code></pre></div><hr><h2 id="二、物理层-vs-数据链路层-回顾对比" tabindex="-1">二、物理层 vs 数据链路层（回顾对比） <a class="header-anchor" href="#二、物理层-vs-数据链路层-回顾对比" aria-label="Permalink to “二、物理层 vs 数据链路层（回顾对比）”">​</a></h2><h3 id="物理层解决" tabindex="-1">物理层解决： <a class="header-anchor" href="#物理层解决" aria-label="Permalink to “物理层解决：”">​</a></h3><blockquote><p><strong>比特（0/1） ↔ 信号（波形）转换</strong></p></blockquote><hr><h3 id="数据链路层解决" tabindex="-1">数据链路层解决： <a class="header-anchor" href="#数据链路层解决" aria-label="Permalink to “数据链路层解决：”">​</a></h3><blockquote><p><strong>数据如何在“一个网络 / 一段链路”内传输</strong></p></blockquote><hr><h2 id="三、什么是-链路-和-网络-重点" tabindex="-1">三、什么是“链路”和“网络”（重点） <a class="header-anchor" href="#三、什么是-链路-和-网络-重点" aria-label="Permalink to “三、什么是“链路”和“网络”（重点）”">​</a></h2><h3 id="_1️⃣-链路-link" tabindex="-1">1️⃣ 链路（Link） <a class="header-anchor" href="#_1️⃣-链路-link" aria-label="Permalink to “1️⃣ 链路（Link）”">​</a></h3><p>👉 定义：</p><blockquote><p>从一个节点到<strong>相邻节点</strong>的一段物理线路</p></blockquote><hr><h3 id="节点包括" tabindex="-1">节点包括： <a class="header-anchor" href="#节点包括" aria-label="Permalink to “节点包括：”">​</a></h3><ul><li>主机（电脑、服务器）</li><li>路由器</li><li>交换机</li><li>集线器</li></ul><hr><h3 id="关键特征" tabindex="-1">关键特征： <a class="header-anchor" href="#关键特征" aria-label="Permalink to “关键特征：”">​</a></h3><ul><li>中间<strong>没有路由器</strong></li><li>可以是： <ul><li>有线（网线）</li><li>无线（WiFi）</li></ul></li></ul><hr><h2 id="四、什么是-同一链路-同一网络" tabindex="-1">四、什么是“同一链路 / 同一网络” <a class="header-anchor" href="#四、什么是-同一链路-同一网络" aria-label="Permalink to “四、什么是“同一链路 / 同一网络””">​</a></h2><p>👉 判断标准：</p><blockquote><p><strong>中间是否经过路由器</strong></p></blockquote><hr><h3 id="✔-同一链路-同一网络" tabindex="-1">✔ 同一链路（同一网络） <a class="header-anchor" href="#✔-同一链路-同一网络" aria-label="Permalink to “✔ 同一链路（同一网络）”">​</a></h3><ul><li>节点之间<strong>没有路由器</strong></li><li>属于同一个局域网（LAN）</li></ul><p>例如：</p><ul><li>主机 ↔ 主机</li><li>主机 ↔ 路由器接口</li></ul><hr><h3 id="❌-不同链路-不同网络" tabindex="-1">❌ 不同链路（不同网络） <a class="header-anchor" href="#❌-不同链路-不同网络" aria-label="Permalink to “❌ 不同链路（不同网络）”">​</a></h3><ul><li>中间<strong>经过路由器</strong></li><li>属于不同网络</li></ul><hr><h2 id="五、案例理解-核心" tabindex="-1">五、案例理解（核心） <a class="header-anchor" href="#五、案例理解-核心" aria-label="Permalink to “五、案例理解（核心）”">​</a></h2><p>假设网络结构：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>主机A ─┬─ 主机B</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └─ 主机C ─ 路由器1 ─ 路由器2 ─ 主机D</span></span></code></pre></div><hr><h3 id="分析" tabindex="-1">分析： <a class="header-anchor" href="#分析" aria-label="Permalink to “分析：”">​</a></h3><h4 id="同一链路-同一网络" tabindex="-1">同一链路（同一网络）： <a class="header-anchor" href="#同一链路-同一网络" aria-label="Permalink to “同一链路（同一网络）：”">​</a></h4><ul><li>主机A、B、C之间 ✔</li><li>主机C 与 路由器1接口 ✔</li></ul><hr><h4 id="不同链路-不同网络" tabindex="-1">不同链路（不同网络）： <a class="header-anchor" href="#不同链路-不同网络" aria-label="Permalink to “不同链路（不同网络）：”">​</a></h4><ul><li>主机A → 主机D ❌（跨多个路由器）</li></ul><hr><h2 id="六、数据链路层的职责-核心" tabindex="-1">六、数据链路层的职责（核心） <a class="header-anchor" href="#六、数据链路层的职责-核心" aria-label="Permalink to “六、数据链路层的职责（核心）”">​</a></h2><p>👉 只负责：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>一个网络（链路）内的数据传输</span></span></code></pre></div><hr><h3 id="举例" tabindex="-1">举例： <a class="header-anchor" href="#举例" aria-label="Permalink to “举例：”">​</a></h3><h4 id="情况1-同一网络通信" tabindex="-1">情况1：同一网络通信 <a class="header-anchor" href="#情况1-同一网络通信" aria-label="Permalink to “情况1：同一网络通信”">​</a></h4><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>主机A → 主机B</span></span></code></pre></div><p>✔ 数据链路层可以<strong>直接完成</strong></p><hr><h4 id="情况2-跨网络通信" tabindex="-1">情况2：跨网络通信 <a class="header-anchor" href="#情况2-跨网络通信" aria-label="Permalink to “情况2：跨网络通信”">​</a></h4><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>主机A → 主机D</span></span></code></pre></div><p>流程：</p><ol><li>数据链路层： <ul><li>A → 路由器1（只负责这一段）</li></ul></li><li>网络层： <ul><li>决定路径（路由）</li></ul></li><li>数据链路层： <ul><li>路由器1 → 路由器2</li><li>路由器2 → 主机D</li></ul></li></ol><hr><h2 id="七、链路层-vs-网络层-关键区别" tabindex="-1">七、链路层 vs 网络层（关键区别） <a class="header-anchor" href="#七、链路层-vs-网络层-关键区别" aria-label="Permalink to “七、链路层 vs 网络层（关键区别）”">​</a></h2><table tabindex="0"><thead><tr><th>层</th><th>作用</th></tr></thead><tbody><tr><td>数据链路层</td><td>负责<strong>一段链路内传输</strong></td></tr><tr><td>网络层</td><td>负责<strong>跨网络传输 + 路由选择</strong></td></tr></tbody></table><hr><h2 id="八、可以这样理解-非常重要" tabindex="-1">八、可以这样理解（非常重要） <a class="header-anchor" href="#八、可以这样理解-非常重要" aria-label="Permalink to “八、可以这样理解（非常重要）”">​</a></h2><p>👉 类比“快递运输”</p><hr><h3 id="数据链路层" tabindex="-1">数据链路层： <a class="header-anchor" href="#数据链路层" aria-label="Permalink to “数据链路层：”">​</a></h3><blockquote><p><strong>负责“这一段路怎么走”</strong></p></blockquote><p>类似：</p><ul><li>一个配送站 → 下一个配送站</li></ul><hr><h3 id="网络层" tabindex="-1">网络层： <a class="header-anchor" href="#网络层" aria-label="Permalink to “网络层：”">​</a></h3><blockquote><p><strong>负责“整体路线规划”</strong></p></blockquote><p>类似：</p><ul><li>从北京 → 上海 的整体路径</li></ul><hr><h2 id="九、总结" tabindex="-1">九、总结 <a class="header-anchor" href="#九、总结" aria-label="Permalink to “九、总结”">​</a></h2><h3 id="核心一句话" tabindex="-1">核心一句话 <a class="header-anchor" href="#核心一句话" aria-label="Permalink to “核心一句话”">​</a></h3><blockquote><p><strong>数据链路层只管局域网（单个链路），网络层才负责跨网络通信</strong></p></blockquote><hr><h3 id="关键记忆点" tabindex="-1">关键记忆点 <a class="header-anchor" href="#关键记忆点" aria-label="Permalink to “关键记忆点”">​</a></h3><ol><li>链路 = 相邻节点之间的物理线路</li><li>是否同一网络 → 看是否经过路由器</li><li>数据链路层： <ul><li>只管“一段路”</li></ul></li><li>网络层： <ul><li>负责“全局路径”</li></ul></li></ol><hr><p>如果你下一步继续学链路层，接下来最关键的就是这两个点（强烈建议你搞懂）：</p><p>👉 <strong>MAC 地址是怎么工作的？</strong> 👉 <strong>ARP 协议为什么必须存在？</strong></p><p>这两个一旦搞懂，你对“链路层”的理解会直接成体系。</p>`,87)])])}const k=l(r,[["render",s]]);export{b as __pageData,k as default};
